from __future__ import annotations

import http.cookiejar
import json
import os
from pathlib import Path
import urllib.error
import urllib.parse
import urllib.request


HTTP_BASE = "http://tails1154.com:9782/cgi-bin/"


class AccountError(RuntimeError):
    pass


class TailsAccountClient:
    """Client for the tails1154 CGI account and external storage service."""

    def __init__(self, cookie_path: Path | None = None) -> None:
        self.cookie_path = cookie_path or (
            Path.home() / ".local" / "share" / "trowser" / "account-cookies.txt"
        )
        self.cookie_path.parent.mkdir(parents=True, exist_ok=True)
        self.cookies = http.cookiejar.MozillaCookieJar(self.cookie_path)
        if self.cookie_path.exists():
            try:
                self.cookies.load(ignore_discard=True, ignore_expires=False)
            except (OSError, http.cookiejar.LoadError):
                pass
        self.opener = urllib.request.build_opener(
            urllib.request.HTTPCookieProcessor(self.cookies)
        )
        self.active_base = HTTP_BASE

    def _request(
        self,
        path: str,
        data: dict[str, str] | None = None,
        timeout: float = 4,
    ) -> str:
        payload = urllib.parse.urlencode(data).encode() if data else None
        try:
            request = urllib.request.Request(HTTP_BASE + path, data=payload)
            with self.opener.open(request, timeout=timeout) as response:
                return response.read().decode("utf-8", errors="replace").strip()
        except (OSError, urllib.error.URLError) as error:
            raise AccountError(f"Account server unavailable: {error}") from error

    def login(self, username: str, password: str) -> str:
        if not username or not password:
            raise AccountError("Enter both a username and password.")
        response = self._request(
            "login.py",
            {"username": username, "password": password},
        )
        if "Login successful!" not in response:
            if "User not found" in response:
                raise AccountError("User not found.")
            raise AccountError("Invalid username or password.")
        account_name = self.username()
        if not account_name:
            raise AccountError("Login succeeded, but the account cookie was rejected.")
        self._save_cookies()
        return account_name

    def username(self) -> str:
        return self._request("username.py")

    def logged_in(self) -> bool:
        return self._request("loggedin.py") == "YES"

    def logout(self) -> None:
        self._request("logout.py")
        self.cookies.clear()
        try:
            self.cookie_path.unlink()
        except FileNotFoundError:
            pass

    def load_sync(self) -> dict:
        response = self._request(
            "getext.py?" + urllib.parse.urlencode({"key": "trowser_sync_v1"})
        )
        if not response:
            return {}
        if response == "ERR":
            raise AccountError("The account server rejected sync access.")
        try:
            data = json.loads(response)
        except json.JSONDecodeError as error:
            raise AccountError("The account contains invalid Trowser sync data.") from error
        return data if isinstance(data, dict) else {}

    def save_sync(self, data: dict) -> None:
        value = json.dumps(data, separators=(",", ":"), ensure_ascii=False)
        if len(value.encode("utf-8")) > 10_000:
            raise AccountError("Sync data exceeds the account service's 10 KB limit.")
        response = self._request(
            "saveext.py", {"key": "trowser_sync_v1", "value": value}
        )
        if response != "OK":
            raise AccountError("The account server rejected the sync update.")

    def _save_cookies(self) -> None:
        self.cookies.save(ignore_discard=True, ignore_expires=False)
        os.chmod(self.cookie_path, 0o600)

    def profile_picture_url(self, username: str) -> str:
        query = urllib.parse.urlencode({"username": username})
        return f"{self.active_base}pfp/get.py?{query}"
